140	// OSExecutor executes commands via os/exec.
141	type OSExecutor struct{}
142	
143	// Execute runs a command and captures output.
144	func (e *OSExecutor) Execute(ctx context.Context, binary string, args []string, stdin string) (*ExecResult, error) {
145		return e.ExecuteInDir(ctx, binary, args, stdin, "")
146	}
