397	func describeRipgrepCommand(fields []string) string {
398		target := ""
399		pattern := ""
400		for _, field := range fields[1:] {
401			if strings.HasPrefix(field, "-") {
402				continue
403			}
404			if pattern == "" {
405				pattern = strings.Trim(field, "'\"")
406				continue
407			}
408			target = field
409		}
410		if target != "" && pattern != "" {
411			return "search " + strconv.Quote(truncateStr(pattern, 32)) + " in " + compactPathToken(target, 36)
412		}
413		if pattern != "" {
414			return "search " + strconv.Quote(truncateStr(pattern, 32))
415		}
416		return "search"
417	}
