519	func compactPathToken(token string, limit int) string {
520		if limit <= 0 || len(token) <= limit || !strings.Contains(token, "/") {
521			return token
522		}
523		prefix, suffix := splitTokenAffixes(token)
524		core := strings.TrimPrefix(strings.TrimSuffix(token, suffix), prefix)
525		if len(core) <= limit || !strings.Contains(core, "/") {
526			return token
527		}
528		parts := strings.Split(core, "/")
529		last := parts[len(parts)-1]
530		if last == "" && len(parts) > 1 {
531			last = parts[len(parts)-2] + "/"
532		}
533		if last == "" {
534			return truncateStr(token, limit)
535		}
536		compacted := "…/" + last
537		if len(prefix)+len(compacted)+len(suffix) <= limit {
538			return prefix + compacted + suffix
539		}
540		return prefix + truncateStr(compacted, maxInt(1, limit-len(prefix)-len(suffix))) + suffix
541	}
542	
543	func splitTokenAffixes(token string) (string, string) {
544		prefix := ""
545		suffix := ""
546		for len(token) > len(prefix) {
547			switch token[len(prefix)] {
548			case '\'', '"', '`', '(', '[', '{':
549				prefix += string(token[len(prefix)])
550			default:
551				goto suffixLoop
552			}
553		}
554	suffixLoop:
555		for len(token) > len(prefix)+len(suffix) {
556			switch token[len(token)-len(suffix)-1] {
557			case '\'', '"', '`', ')', ']', '}', ',', ';':
558				suffix = string(token[len(token)-len(suffix)-1]) + suffix
559			default:
560				return prefix, suffix
561			}
562		}
563		return prefix, suffix
564	}
