585		for _, prefix := range []string{`{command=`, `{"command":`} {
586			if !strings.HasPrefix(display, prefix) {
587				continue
588			}
589			value := strings.TrimPrefix(display, prefix)
590			value = strings.TrimSuffix(value, "}")
591			value = strings.TrimSpace(value)
592			if unquoted, err := strconv.Unquote(value); err == nil {
593				return unquoted
594			}
595			return strings.Trim(value, `"`)
596		}
597		return display
598	}
