121	// executeOnService dispatches against a pre-built svc using the durable
122	// knobs from rcfg and per-invocation plumbing from runtime, then records
123	// one session-index row. It is the inlined replacement for the retired
124	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
125	func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
126		if svc == nil {
127			return nil, fmt.Errorf("agent: nil service")
128		}
129		if ctx == nil {
130			ctx = context.Background()
131		}
132	
133		promptText := runtime.Prompt
134		if runtime.PromptFile != "" {
135			data, err := readPromptFileBounded(runtime.PromptFile)
136			if err != nil {
137				return nil, fmt.Errorf("agent: read prompt file: %w", err)
138			}
139			promptText = string(data)
140		}
141		if promptText == "" {
142			return nil, fmt.Errorf("agent: prompt is required")
143		}
144	
145		wd := runtime.WorkDir
146		if wd == "" {
147			wd = workDir
148		}
149		if wd == "" {
150			wd, _ = os.Getwd()
151		}
152	
153		idle := rcfg.Timeout()
154		if idle <= 0 {
155			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
156		}
157		wall := rcfg.WallClock()
158		if wall <= 0 {
159			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
160		}
161	
162		sessionLogDir := runtime.SessionLogDirOverride
163		if sessionLogDir == "" {
164			sessionLogDir = rcfg.SessionLogDir()
165		}
166		if sessionLogDir == "" {
167			sessionLogDir = ResolveLogDir(workDir, "")
168		}
169	
170		pt := rcfg.Passthrough()
171	
172		harness := runtime.HarnessOverride
173		if harness == "" && !runtime.ClearRoutingPins {
174			harness = pt.Harness
175		}
176	
177		model := runtime.ModelOverride
178		if model == "" && !runtime.ClearRoutingPins {
179			model = pt.Model
180		}
181	
182		modelRef := runtime.ModelRefOverride
183		if modelRef == "" && !runtime.ClearRoutingPins {
184			modelRef = rcfg.ModelRef()
185		}
186	
187		provider := pt.Provider
188		if runtime.ClearRoutingPins {
189			provider = ""
190		}
191	
192		profile := runtime.ProfileOverride
193		if profile == "" && !runtime.ClearProfile {
194			profile = rcfg.Profile()
195		}
196	
197		permissions := runtime.PermissionsOverride
198		if permissions == "" {
199			permissions = rcfg.Permissions()
200		}
201	
202		providerTimeout := ResolveProviderRequestTimeout(workDir, provider, model, rcfg.ProviderRequestTimeout())
203	
204		minPower := rcfg.MinPower()
205		if runtime.MinPowerOverride > 0 {
206			minPower = runtime.MinPowerOverride
207		}
208		if runtime.ClearMinPower {
209			minPower = 0
210		}
211		maxPower := rcfg.MaxPower()
212		if runtime.ClearMaxPower {
213			maxPower = 0
214		}
215		if minPower > 0 && maxPower > 0 && minPower >= maxPower {
216			return nil, fmt.Errorf("agent: invalid power bounds: min_power=%d must be less than max_power=%d", minPower, maxPower)
217		}
218	
219		req := agentlib.ServiceExecuteRequest{
220			Prompt:          promptText,
221			Model:           model,
222			Profile:         profile,
223			Provider:        provider,
224			Harness:         harness,
225			ModelRef:        modelRef,
226			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
227			Permissions:     permissions,
228			WorkDir:         wd,
229			Timeout:         wall,
230			IdleTimeout:     idle,
231			ProviderTimeout: providerTimeout,
232			SessionLogDir:   sessionLogDir,
233			Metadata:        metadataWithEnv(runtime.Correlation, runtime.Env),
234			Role:            runtime.Role,
235			CorrelationID:   runtime.CorrelationID,
236			MinPower:        minPower,
237			MaxPower:        maxPower,
238		}
239	
240		cancelCtx, cancel := context.WithCancel(ctx)
241		defer cancel()
242	
243		// When Harness is set and Model is empty, fizeau routes within the harness's
244		// eligible models using Profile/MinPower as the routing constraint. This is the
245		// well-formed request shape for profile-driven dispatch without an explicit model.
246		// fizeau returns ErrHarnessModelIncompatible (typed, non-nil) on pre-dispatch
247		// errors and a failed final event for post-dispatch errors.
248		start := time.Now().UTC()
249		events, err := svc.Execute(cancelCtx, req)
250		if err != nil {
251			return nil, fmt.Errorf("agent: execute: %w", err)
252		}
253	
254		renderer := NewWorkLogRenderer(WorkLogRendererOptions{
255			CurrentBeadID: runtime.Correlation["bead_id"],
256			WorkPhase:     "do",
257		})
258		final, routing, _ := drainServiceEventsWithRenderer(events, runtime.Output, renderer)
259		finishedAt := time.Now().UTC()
260		elapsed := finishedAt.Sub(start)
261	
262		result := &Result{
263			Harness:    harness,
264			Model:      model,
265			DurationMS: int(elapsed.Milliseconds()),
266		}
267		if routing != nil {
268			result.Provider = routing.Provider
269			if routing.Model != "" {
270				result.Model = routing.Model
271			}
272			if routing.Harness != "" {
273				result.Harness = routing.Harness
274			}
275			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
276				result.PredictedPower = power
277				result.PredictedSpeedTPS = speed
278				result.PredictedCostUSDPer1kTokens = cost
279				result.PredictedCostSource = source
280			}
281		}
282		if final != nil {
283			// Normalized final text from the upstream harness (agent-32e8ff5e);
284			// reviewer verdict extraction now parses this instead of raw stream
285			// frames (ddx-7bc0c8d5).
286			result.Output = final.FinalText
287			if final.Usage != nil {
288				// v0.9.1: Usage fields became *int (nullable).
289				if final.Usage.InputTokens != nil {
290					result.InputTokens = *final.Usage.InputTokens
291				}
292				if final.Usage.OutputTokens != nil {
293					result.OutputTokens = *final.Usage.OutputTokens
294				}
295				if final.Usage.TotalTokens != nil {
296					result.Tokens = *final.Usage.TotalTokens
297				}
298			}
299			if final.CostUSD > 0 {
300				result.CostUSD = final.CostUSD
301			}
302			result.ExitCode = final.ExitCode
303			result.Error = final.Error
304			if final.RoutingActual != nil {
305				if result.Provider == "" {
306					result.Provider = final.RoutingActual.Provider
307				}
308				if final.RoutingActual.Model != "" {
309					result.Model = final.RoutingActual.Model
310				}
311				if final.RoutingActual.Harness != "" {
312					result.Harness = final.RoutingActual.Harness
313				}
314				if final.RoutingActual.Power > 0 {
315					result.ActualPower = final.RoutingActual.Power
316				}
317			}
318			if final.SessionLogPath != "" {
319				result.AgentSessionID = final.SessionLogPath
320			}
321		}
322		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
323		normalizeServiceFinalExitCode(result)
324		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
325			Harness:     harness,
326			Model:       model,
327			Provider:    provider,
328			Effort:      rcfg.Effort(),
329			Correlation: runtime.Correlation,
330		}, result, start, finishedAt)
331		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
332		return result, nil
333	}
