358	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
359	// querying the service's ListHarnesses and (best-effort) the harness registry.
360	// It is the production replacement for Runner.Capabilities.
361	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
362		if ctx == nil {
363			ctx = context.Background()
364		}
365		svc, err := NewServiceFromWorkDir(workDir)
366		if err != nil {
367			return nil, fmt.Errorf("agent: build service: %w", err)
368		}
369		infos, err := svc.ListHarnesses(ctx)
370		if err != nil {
371			return nil, fmt.Errorf("agent: list harnesses: %w", err)
372		}
373		var info *agentlib.HarnessInfo
374		for i := range infos {
375			if infos[i].Name == harnessName {
376				info = &infos[i]
377				break
378			}
379		}
380		if info == nil {
381			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
382		}
383	
384		// Pull binary and reasoning-level metadata from the local registry — the
385		// service does not expose these directly today.
386		registry := newHarnessRegistry()
387		harness, _ := registry.Get(harnessName)
388	
389		caps := &HarnessCapabilities{
390			Harness:             info.Name,
391			Available:           info.Available,
392			Binary:              harness.Binary,
393			Path:                info.Path,
394			Surface:             harness.Surface,
395			CostClass:           info.CostClass,
396			IsLocal:             info.IsLocal,
397			ExactPinSupport:     info.ExactPinSupport,
398			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
399			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
400		}
401		if len(info.SupportedReasoning) > 0 {
402			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
403		} else if len(harness.ReasoningLevels) > 0 {
404			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
405		}
406	
407		if harness.DefaultModel != "" {
408			caps.Model = harness.DefaultModel
409			caps.Models = []string{harness.DefaultModel}
410		}
411	
412		return caps, nil
413	}
